#include<bits/stdc++.h>
using namespace std;
vector<int>v1;
long long a,b,p;
int quick_power(int a,int b){
	long long ans=1;
	long long base=a;
	while(b>0){
		if(b%2){
			ans*=base;
			ans%=p;
		}
		base*=base;
		base%=p;
		b/=2;
	}
	return ans;
}
int main()
{
	long long t;
	cin>>t;
	while(t--){		
		cin>>a>>p;
		v1.clear();
		for(int i=2;i*i<=p-1;i++){

			if(!((p-1)%i)){
//                cout<<i<<endl;
				v1.push_back(i);
				v1.push_back((p-1)/i);
			}			
		}
		int flag=0;
		for(int i:v1){
//            cout<<i<<endl;
			if(quick_power(a,i)==1){
				cout<<"No"<<endl;
				flag=1;
				break;
			}
		}
		if(!flag)cout<<"Yes"<<endl; 
	}
}
